fixes.origin:
char command[512];

/* Build tar command */
snprintf(command, sizeof(command), "tar -czf backup.tgz %s", directory);

/* Execute system command */
int result = system(command);

if (result != 0) {
    fprintf(stderr, "Archive creation failed\n");
    return -1;
}

return 0;

fixes.replacement:
char *args[] = { "tar", "-czf", "backup.tgz", (char *)directory, NULL };
execvp("tar", args);
perror("execvp");
return -1;
